+        let cx_sq = cx
+            .elementwise_binary(&cx, fnp_ufunc::BinaryOp::Mul)
+            .expect("sq");
+        let norm_cx = cx_sq
+            .reduce_sum(None, false)
+            .expect("sum")
+            .elementwise_unary(fnp_ufunc::UnaryOp::Sqrt);
+        let expected = norm_x.values()[0] * c.abs();
+        assert!(
+            (norm_cx.values()[0] - expected).abs() < 1e-10,
+            "norm homogeneity: {} != {}",
+            norm_cx.values()[0],
+            expected
